class Solution:
 def is_possible(self, nums: list[int]) -> bool:
 stack1, stack2 = [], []
 total_sum = sum(nums)
 half_sum = total_sum // 2
 for num in nums:
 stack1.append(num)
 stack2.append(num)
 while stack1 and stack2 and sum(stack1) + sum(stack2) > half_sum:
 if stack1[-1] > stack2[-1]:
 stack1.pop()
 else:
 stack2.pop()
 if sum(stack1) + sum(stack2) == half_sum:
 return True
 return False

solutions.cpp:
class Solution {
 public: bool isPossible(int\* nums, int n) {
 stack<int> stack1, stack2;
 int total_sum = 0;
 for (int i = 0; i < n; i++) {
 total_sum += nums[i];
 }
 int half_sum = total_sum / 2;
 for (int i = 0; i < n; i++) {
 stack1.push(nums[i]);
 stack2.push(nums[i]);
 }
 while (!stack1.empty() && !stack2.empty() && (stack1.top() + stack2.top()) > half_sum) {
 if (stack1.top() > stack2.top()) {
 stack1.pop();
 } else {
 stack2.pop();
 }
 if (stack1.top() + stack2.top() == half_sum) {
 return true;
 }
 }
 return false;
 }
};
